LXImport("..Struct.StructTemplate")

local LModel = LModel
------------------------------------------------------------------
---@class ModelDYFeed:LModel
local ModelDYFeed = LxClass("ModelDYFeed",LModel)
------------------------------------------------------------------

--- 离线收益
ModelDYFeed.SCENE_OFFLINE = 1
--- 体力恢复
ModelDYFeed.SCENE_RECOVER = 2
--- 重要事件
ModelDYFeed.SCENE_IMPORTANCE = 3

ModelDYFeed.SCENE_2_CONTENTID = {
	[ModelDYFeed.SCENE_OFFLINE] = "CONTENT13415123970",
	[ModelDYFeed.SCENE_RECOVER] = "CONTENT13834906882",
	[ModelDYFeed.SCENE_IMPORTANCE] = "CONTENT13834755330",
}


function ModelDYFeed:ModelDYFeed()
	self._recordId = nil
	self._onlineTimer = nil
end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelDYFeed:OnModelInit()
	---@type table<string,boolean> 已完成订阅的玩家id列表
	self._finishPlayerIdMap = {}
	self:ModelNetMsgRecv(LProtoIds.GoldBuyResp,function(...)
        self:CheckFeedSubscribeRecover()
	end)
	self:ModelNetMsgRecv(LProtoIds.InstancePlaceRewardResp,function(...)
		self:OnRequestFeedSubscribeOffline()
	end)
end

--在协议数据处理完之后需要调用finish
function ModelDYFeed:OnModelRequest()
	self:ModelFinish()
end


function ModelDYFeed:NeedCheckFeed()
	return CS.IsWebGL() and LWxHelper.IsDouYinPlatform()
end

--- 在线时长
function ModelDYFeed:StartOnlineTimer(playerId)
	if not self:NeedCheckFeed() then return end

	if not playerId then return end

	local checkOnlineTime = checknumber(LPlayerPrefs.checkOnlineTime) or 0
	if checkOnlineTime ~= 0 then
		if LUtil.IsToDay(checkOnlineTime) then return end
	end
	
	if self._finishPlayerIdMap[playerId] then
		self:ClearOnlineTimer()
		return
	end
	
	if self._recordId and self._recordId == playerId and self._onlineTimer then
		return
	end

	-- 在线满30分钟触发
	self._recordId = playerId
	self:ClearOnlineTimer()
	self._onlineTimer = LxTimer.DelayTimeCall(function() 
		self:OnRequestFeedSubscribeOnline()
		self._recordId = nil
		self._finishPlayerIdMap[playerId] = true
		LPlayerPrefs.SetCheckOnlineTime(GetTimestamp())
		self:ClearOnlineTimer()
	end, 30*60,false)
end


function ModelDYFeed:ClearOnlineTimer()
	local timer = self._onlineTimer
	if timer then
		LxTimer.DelayTimeStop(timer)
		self._onlineTimer = nil
	end
end

function ModelDYFeed:GetContentIdByScene(scene)
	return ModelDYFeed.SCENE_2_CONTENTID[scene]
end

function ModelDYFeed:OnRequestFeedSubscribeOnline()
	local scene = ModelDYFeed.SCENE_OFFLINE
	local contentId = self:GetContentIdByScene(scene)
	if string.isempty(contentId) then return end
	
	gLSdkImpl:CallMethod(LSdkMethod.RequestFeedSubscribe,scene,contentId)
end

function ModelDYFeed:CheckFeedSubscribeByScene(scene)
	if not self:NeedCheckFeed() then return end
	gLSdkImpl:CallMethod(LSdkMethod.CheckFeedSubscribe,scene)
end

function ModelDYFeed:CheckFeedSubscribeOffline()
	if not self:NeedCheckFeed() then return end
	self:CheckFeedSubscribeByScene(ModelDYFeed.SCENE_OFFLINE)
end

function ModelDYFeed:CheckFeedSubscribeRecover()
	if not self:NeedCheckFeed() then return end
	
	--- 祷告金币后触发，每日1次
	local openGoldBuyTime = checknumber(LPlayerPrefs.openGoldBuyTime) or 0
	if openGoldBuyTime ~= 0 then
		if LUtil.IsToDay(openGoldBuyTime) then return end
	end
	self:CheckFeedSubscribeByScene(ModelDYFeed.SCENE_RECOVER)
end

function ModelDYFeed:CheckFeedSubscribeImportance()
	if not self:NeedCheckFeed() then return end
	
	--- 每次第一次点击左下角活动界面
	local checkImportanceTime = checknumber(LPlayerPrefs.checkImportanceTime) or 0
	if checkImportanceTime ~= 0 then
		if LUtil.IsToDay(checkImportanceTime) then return end
	end
	self:CheckFeedSubscribeByScene(ModelDYFeed.SCENE_IMPORTANCE)
end

function ModelDYFeed:OnRequestFeedSubscribeByScene(scene)
	local contentId = self:GetContentIdByScene(scene)
	if string.isempty(contentId) then return end

	if scene == ModelDYFeed.SCENE_RECOVER then
		LPlayerPrefs.SetOpenGoldBuyTime(GetTimestamp())
	elseif scene == ModelDYFeed.SCENE_IMPORTANCE then
		LPlayerPrefs.SetCheckImportanceTime(GetTimestamp())
	end

	gLSdkImpl:CallMethod(LSdkMethod.RequestFeedSubscribe,scene,contentId)
end

function ModelDYFeed:DisposeRequestFeedSubscribe(scene)
    --- 未订阅，启动检测
	if scene == ModelDYFeed.SCENE_OFFLINE then
		--- 喵管家修改为点击触发，不使用定时器
		--self:StartOnlineTimer(gModelPlayer:GetPlayerId())
	else
		self:OnRequestFeedSubscribeByScene(scene)
	end
end

function ModelDYFeed:OnRequestFeedSubscribeOffline()
	if not self:NeedCheckFeed() then return end

	--- 领取离线奖励时间，每日1次
	local clickOnlineTime = checknumber(LPlayerPrefs.clickOnlineTime) or 0
	if clickOnlineTime ~= 0 then
		if LUtil.IsToDay(clickOnlineTime) then return end
	end
	LPlayerPrefs.SetClickOnlineTime(GetTimestamp())
	self:OnRequestFeedSubscribeOnline()
end

--清理工作
--停止计时器之类的
function ModelDYFeed:OnModelClear()
	self:ClearOnlineTimer()
end

return ModelDYFeed